import React, { useState, useEffect } from 'react';
import { Menu, X, Terminal } from 'lucide-react';
import { NAV_ITEMS } from '../constants';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-white/90 backdrop-blur-md shadow-md py-3' : 'bg-transparent py-5'}`}>
      <div className="container mx-auto px-4 md:px-8 flex justify-between items-center">
        {/* Logo */}
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => window.scrollTo(0,0)}>
          <div className="bg-primary-600 p-2 rounded-lg text-white">
            <Terminal size={24} />
          </div>
          <span className={`text-xl font-bold ${isScrolled ? 'text-slate-900' : 'text-slate-900 md:text-white'}`}>
            SyncTech
          </span>
        </div>

        {/* Desktop Nav */}
        <div className="hidden md:flex items-center gap-8">
          {NAV_ITEMS.map((item) => (
            <a 
              key={item.label} 
              href={item.href} 
              className={`font-medium hover:text-primary-500 transition-colors ${isScrolled ? 'text-slate-600' : 'text-slate-200'}`}
            >
              {item.label}
            </a>
          ))}
          <a 
            href="#contact" 
            className="px-5 py-2 bg-primary-600 text-white rounded-full font-medium hover:bg-primary-700 transition-transform transform hover:scale-105"
          >
            Get a Quote
          </a>
        </div>

        {/* Mobile Toggle */}
        <button 
          className="md:hidden text-slate-600"
          onClick={() => setIsOpen(!isOpen)}
        >
          {isOpen ? <X size={28} /> : <Menu size={28} className={isScrolled ? 'text-slate-800' : 'text-slate-800'} />} 
          {/* Note: text color on mobile hamburger needs visibility against hero bg if transparent. 
              Assuming hero image is dark, white is better, but sticky is white bg. 
              Let's force slate-800 for mobile menu toggle for simplicity/safety against light images.
          */}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-lg py-4 px-4 flex flex-col gap-4 border-t border-slate-100">
          {NAV_ITEMS.map((item) => (
            <a 
              key={item.label} 
              href={item.href} 
              className="text-slate-600 font-medium py-2 border-b border-slate-50 last:border-0"
              onClick={() => setIsOpen(false)}
            >
              {item.label}
            </a>
          ))}
          <a 
            href="#contact" 
            className="w-full text-center py-3 bg-primary-600 text-white rounded-lg font-bold"
            onClick={() => setIsOpen(false)}
          >
            Get Free Consultation
          </a>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

