    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-slate-950/80 backdrop-blur-md shadow-lg shadow-black/20 py-3 border-b border-white/5' : 'bg-transparent py-5'}`}>
      <div className="container mx-auto px-4 md:px-8 flex justify-between items-center">
        {/* Logo */}
        <div className="flex items-center gap-2 cursor-pointer group" onClick={() => window.scrollTo(0,0)}>
          <div className="bg-primary-600 p-2 rounded-lg text-white group-hover:bg-primary-500 transition-colors">
            <Terminal size={24} />
          </div>
          <span className="text-xl font-bold text-white tracking-tight">
            SyncTech
          </span>
        </div>

        {/* Desktop Nav */}
        <div className="hidden md:flex items-center gap-8">
          {NAV_ITEMS.map((item) => (
            <a 
              key={item.label} 
              href={item.href} 
              className="font-medium text-slate-300 hover:text-primary-400 transition-colors"
            >
              {item.label}
            </a>
          ))}
          <a 
            href="#contact" 
            className="px-5 py-2 bg-primary-600 text-white rounded-full font-medium hover:bg-primary-500 transition-all transform hover:scale-105 shadow-lg shadow-primary-500/20"
          >
            Get a Quote
          </a>
        </div>

        {/* Mobile Toggle */}
        <button 
          className="md:hidden text-white"
          onClick={() => setIsOpen(!isOpen)}
        >
          {isOpen ? <X size={28} /> : <Menu size={28} />} 
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-slate-900 shadow-xl py-4 px-4 flex flex-col gap-4 border-t border-slate-800">
          {NAV_ITEMS.map((item) => (
            <a 
              key={item.label} 
              href={item.href} 
              className="text-slate-300 font-medium py-2 border-b border-slate-800 last:border-0 hover:text-primary-400"
              onClick={() => setIsOpen(false)}
            >
              {item.label}
            </a>
          ))}
          <a 
            href="#contact" 
            className="w-full text-center py-3 bg-primary-600 text-white rounded-lg font-bold hover:bg-primary-500"
            onClick={() => setIsOpen(false)}
          >
            Get Free Consultation
          </a>
        </div>
      )}
    </nav>
  );
};

